Every INSERT uses ON CONFLICT … DO NOTHING (or WHERE NOT EXISTS) -- so the entire script is safe to re-run without producing duplicates.

-- publishers (6 rows) INSERT INTO bookstore.publishers (name, country, founded_year, website) VALUES ('Penguin Random House', 'United States', 1927, 'https://www.penguinrandomhouse.com'), ('HarperCollins', 'United States', 1989, 'https://www.harpercollins.com'), ('Simon & Schuster', 'United States', 1924, 'https://www.simonandschuster.com'), ('Bloomsbury Publishing', 'United Kingdom', 1986, 'https://www.bloomsbury.com'), ('MIT Press', 'United States', 1962, 'https://mitpress.mit.edu'), ('Macmillan Publishers', 'United Kingdom', 1843, 'https://www.macmillan.com') ON CONFLICT (name) DO NOTHING;

-- authors (8 rows) INSERT INTO bookstore.authors (first_name, last_name, birth_date, nationality, gender, bio) VALUES ('George', 'Orwell', '1903-06-25', 'British', 'Male', 'English novelist best known for Nineteen Eighty-Four and Animal Farm.'), ('Toni', 'Morrison', '1931-02-18', 'American', 'Female', 'Nobel Prize-winning novelist celebrated for Beloved.'), ('Haruki', 'Murakami', '1949-01-12', 'Japanese', 'Male', 'Japanese author whose fiction blends everyday realism with surreal elements.'), ('Chimamanda', 'Adichie', '1977-09-15', 'Nigerian', 'Female', 'Author acclaimed for Americanah and Half of a Yellow Sun.'), ('Stephen', 'King', '1947-09-21', 'American', 'Male', 'Prolific master of horror, suspense, and supernatural fiction.'), ('Yuval Noah', 'Harari', '1976-02-24', 'Israeli', 'Male', 'Historian and author of the internationally bestselling Sapiens trilogy.'), ('Zadie', 'Smith', '1975-10-25', 'British', 'Female', 'Novelist and essayist best known for White Teeth.'), ('Colson', 'Whitehead', '1969-11-06', 'American', 'Male', 'Pulitzer Prize-winning author of The Underground Railroad.') ON CONFLICT (first_name, last_name) DO NOTHING;

-- genres (7 rows) INSERT INTO bookstore.genres (name, description) VALUES ('Dystopian Fiction', 'Fiction set in oppressive, often futuristic societies.'), ('Literary Fiction', 'Character-driven prose with strong thematic depth.'), ('Magical Realism', 'Realistic settings interwoven with fantastical elements.'), ('Horror', 'Fiction crafted to frighten, disturb, or unsettle the reader.'), ('Non-Fiction', 'Factual works covering history, science, biography, and more.'), ('Contemporary Fiction', 'Modern-day fiction featuring realistic characters and settings.'), ('Historical Fiction', 'Narrative fiction set within a carefully researched historical period.') ON CONFLICT (name) DO NOTHING;

-- books (8 rows) -- publisher_id is resolved by publisher name via JOIN — no hardcoded IDs. INSERT INTO bookstore.books (title, isbn, publisher_id, publication_date, price, format, pages, stock_quantity) SELECT v.title, v.isbn, p.publisher_id, v.pub_date, v.price, v.fmt, v.pages, v.stock FROM (VALUES ('Nineteen Eighty-Four', '978-0-452-28423-4', 'Penguin Random House', DATE '2003-05-06', 12.99, 'paperback', 328, 45), ('Beloved', '978-1-4000-3341-6', 'Penguin Random House', DATE '2004-06-08', 14.99, 'paperback', 321, 30), ('Norwegian Wood', '978-0-375-70402-1', 'Penguin Random House', DATE '2001-08-14', 15.00, 'paperback', 296, 20), ('Americanah', '978-0-307-45527-8', 'Penguin Random House', DATE '2013-05-14', 16.00, 'hardcover', 477, 25), ('The Shining', '978-0-385-12167-5', 'Simon & Schuster', DATE '2002-01-28', 13.99, 'paperback', 447, 50), ('Sapiens: A Brief History of Humankind', '978-0-062-31609-7', 'HarperCollins', DATE '2015-02-10', 18.99, 'hardcover', 443, 60), ('White Teeth', '978-0-375-70384-0', 'Penguin Random House', DATE '2001-03-27', 14.00, 'paperback', 448, 15), ('The Underground Railroad', '978-0-385-54232-2', 'Penguin Random House', DATE '2016-08-02', 15.99, 'hardcover', 320, 35) ) AS v(title, isbn, publisher_name, pub_date, price, fmt, pages, stock) JOIN bookstore.publishers p ON p.name = v.publisher_name WHERE NOT EXISTS ( SELECT 1 FROM bookstore.books b WHERE b.isbn = v.isbn );

-- book_authors (8 rows) — M2M -- Both book_id and author_id resolved via natural keys; no hardcoding. INSERT INTO bookstore.book_authors (book_id, author_id) SELECT b.book_id, a.author_id FROM (VALUES ('978-0-452-28423-4', 'Orwell'), ('978-1-4000-3341-6', 'Morrison'), ('978-0-375-70402-1', 'Murakami'), ('978-0-307-45527-8', 'Adichie'), ('978-0-385-12167-5', 'King'), ('978-0-062-31609-7', 'Harari'), ('978-0-375-70384-0', 'Smith'), ('978-0-385-54232-2', 'Whitehead') ) AS v(isbn, last_name) JOIN bookstore.books b ON b.isbn = v.isbn JOIN bookstore.authors a ON a.last_name = v.last_name ON CONFLICT DO NOTHING;

-- book_genres (14 rows) — M2M -- Several books intentionally span multiple genres to exercise the junction table. INSERT INTO bookstore.book_genres (book_id, genre_id) SELECT b.book_id, g.genre_id FROM (VALUES ('978-0-452-28423-4', 'Dystopian Fiction'), ('978-0-452-28423-4', 'Literary Fiction'), ('978-1-4000-3341-6', 'Literary Fiction'), ('978-1-4000-3341-6', 'Historical Fiction'), ('978-0-375-70402-1', 'Literary Fiction'), ('978-0-375-70402-1', 'Magical Realism'), ('978-0-307-45527-8', 'Contemporary Fiction'), ('978-0-307-45527-8', 'Literary Fiction'), ('978-0-385-12167-5', 'Horror'), ('978-0-062-31609-7', 'Non-Fiction'), ('978-0-375-70384-0', 'Contemporary Fiction'), ('978-0-375-70384-0', 'Literary Fiction'), ('978-0-385-54232-2', 'Historical Fiction'), ('978-0-385-54232-2', 'Literary Fiction') ) AS v(isbn, genre_name) JOIN bookstore.books b ON b.isbn = v.isbn JOIN bookstore.genres g ON g.name = v.genre_name ON CONFLICT DO NOTHING;

-- customers (6 rows) INSERT INTO bookstore.customers (first_name, last_name, email, phone, gender, registration_date, birth_date) VALUES ('James', 'Harrison', 'james.harrison@email.com', '+1-202-555-0143', 'Male', '2021-03-15', '1988-07-22'), ('Sofia', 'Reyes', 'sofia.reyes@email.com', '+34-91-555-0187', 'Female', '2020-11-08', '1994-03-10'), ('David', 'Nakamura', 'david.nakamura@email.com', '+81-3-5555-0192', 'Male', '2022-01-20', '1990-12-05'), ('Amara', 'Okafor', 'amara.okafor@email.com', '+234-1-555-0176', 'Female', '2021-07-11', '1997-09-30'), ('Luca', 'Ferrari', 'luca.ferrari@email.com', '+39-06-5550-1234', 'Male', '2023-02-28', '1985-05-17'), ('Nadia', 'Petrova', 'nadia.petrova@email.com', '+7-495-555-0198', 'Female', '2020-05-19', '1992-11-28') ON CONFLICT (email) DO NOTHING;

-- orders (6 rows) -- customer_id resolved by email via JOIN — no hardcoded IDs. INSERT INTO bookstore.orders (customer_id, order_date, status, total_amount, shipping_address) SELECT c.customer_id, v.order_date, v.status, v.total_amount, v.address FROM (VALUES ('james.harrison@email.com', DATE '2024-03-10', 'delivered', 27.98, '142 Oak Street, Washington DC, USA'), ('sofia.reyes@email.com', DATE '2024-04-05', 'shipped', 18.99, 'Calle Mayor 23, Madrid, Spain'), ('david.nakamura@email.com', DATE '2024-05-20', 'confirmed', 15.00, '3-7 Shinjuku, Tokyo, Japan'), ('amara.okafor@email.com', DATE '2024-06-01', 'pending', 16.00, '14 Victoria Island, Lagos, Nigeria'), ('luca.ferrari@email.com', DATE '2024-06-15', 'delivered', 27.99, 'Via Roma 77, Rome, Italy'), ('nadia.petrova@email.com', DATE '2024-07-03', 'cancelled', 13.99, 'Tverskaya 12, Moscow, Russia') ) AS v(email, order_date, status, total_amount, address) JOIN bookstore.customers c ON c.email = v.email WHERE NOT EXISTS ( SELECT 1 FROM bookstore.orders o WHERE o.customer_id = c.customer_id AND o.order_date = v.order_date );

-- order_items (8 rows) -- All foreign keys resolved by natural keys via JOIN — no hardcoded IDs. -- subtotal is auto-computed by the GENERATED ALWAYS AS expression. INSERT INTO bookstore.order_items (order_id, book_id, quantity, unit_price) SELECT o.order_id, b.book_id, v.qty, v.unit_price FROM (VALUES ('james.harrison@email.com', DATE '2024-03-10', '978-0-452-28423-4', 1, 12.99), ('james.harrison@email.com', DATE '2024-03-10', '978-1-4000-3341-6', 1, 14.99), ('sofia.reyes@email.com', DATE '2024-04-05', '978-0-062-31609-7', 1, 18.99), ('david.nakamura@email.com', DATE '2024-05-20', '978-0-375-70402-1', 1, 15.00), ('amara.okafor@email.com', DATE '2024-06-01', '978-0-307-45527-8', 1, 16.00), ('luca.ferrari@email.com', DATE '2024-06-15', '978-0-385-12167-5', 1, 13.99), ('luca.ferrari@email.com', DATE '2024-06-15', '978-0-375-70384-0', 1, 14.00), ('nadia.petrova@email.com', DATE '2024-07-03', '978-0-385-12167-5', 1, 13.99) ) AS v(email, order_date, isbn, qty, unit_price) JOIN bookstore.customers c ON c.email = v.email JOIN bookstore.orders o ON o.customer_id = c.customer_id AND o.order_date = v.order_date JOIN bookstore.books b ON b.isbn = v.isbn ON CONFLICT (order_id, book_id) DO NOTHING;

-- reviews (6 rows) -- customer_id and book_id resolved by natural keys — no hardcoded IDs. INSERT INTO bookstore.reviews (customer_id, book_id, rating, comment, review_date) SELECT c.customer_id, b.book_id, v.rating, v.comment, v.review_date FROM (VALUES ('james.harrison@email.com', '978-0-452-28423-4', 5, 'A timeless masterpiece — haunting and absolutely essential.', DATE '2024-03-20'), ('sofia.reyes@email.com', '978-0-062-31609-7', 4, 'Thought-provoking and meticulously researched.', DATE '2024-04-12'), ('david.nakamura@email.com', '978-0-375-70402-1', 5, 'Deeply moving; Murakami at his most lyrical and melancholic.', DATE '2024-05-28'), ('amara.okafor@email.com', '978-0-307-45527-8', 5, 'A brilliant and honest portrayal of identity and belonging.', DATE '2024-06-09'), ('luca.ferrari@email.com', '978-0-385-12167-5', 4, 'Genuinely unsettling from the very first chapter.', DATE '2024-06-22'), ('nadia.petrova@email.com', '978-0-452-28423-4', 3, 'Important and relevant, but the pacing drags in the middle.', DATE '2024-07-10') ) AS v(email, isbn, rating, comment, review_date) JOIN bookstore.customers c ON c.email = v.email JOIN bookstore.books b ON b.isbn = v.isbn ON CONFLICT (customer_id, book_id) DO NOTHING;

